import asyncio
import websockets
from collections import defaultdict

class Inventory:
    def __init__(self):
        self.items = defaultdict(int)

    async def add_item(self, item_id, quantity):
        self.items[item_id] += quantity

    async def remove_item(self, item_id, quantity):
        if self.items[item_id] >= quantity:
            self.items[item_id] -= quantity
            return True
        return False

class Player:
    def __init__(self, player_id):
        self.player_id = player_id
        self.inventory = Inventory()

class GameServer:
    def __init__(self):
        self.players = {}
        self.connections = set()

    async def register_player(self, websocket, path):
        player_id = await websocket.recv()
        if player_id not in self.players:
            self.players[player_id] = Player(player_id)
        self.connections.add(websocket)

    async def handle_trade_request(self, websocket, item_id, quantity):
        player_id = next((player.player_id for player in self.players.values() if player.inventory.items == websocket), None)
        if player_id:
            success = await self.players[player_id].inventory.remove_item(item_id, quantity)
            if success:
                await websocket.send(f"Item {item_id} removed from inventory")
                await self.broadcast_trade_update(player_id, item_id, -quantity)

    async def broadcast_trade_update(self, sender_id, item_id, quantity):
        for player in self.players.values():
            if player.player_id != sender_id and player.inventory.items == sender_id:
                await player.inventory.add_item(item_id, quantity)
                await player.connection.send(f"Item {item_id} added to inventory")

    async def main(self):
        async with websockets.serve(self.register_player, "localhost", 8765):
            while True:
                await asyncio.sleep(1)

if __name__ == "__main__":
    server = GameServer()
    asyncio.run(server.main())